$pageTitle='My Tuition Posts';require __DIR__.'/../includes/header.php';require_role(['student','guardian']);$stmt=$pdo->prepare('SELECT t.*,(SELECT COUNT(*) FROM applications a WHERE a.tuition_id=t.id) app_count FROM tuition_posts t WHERE t.user_id=? ORDER BY t.created_at DESC');$stmt->execute([current_user()['id']]);$rows=$stmt->fetchAll();
?>
<div class="container py-5"><div class="d-flex justify-content-between align-items-center"><div><h1 class="section-title">My Tuition Posts</h1><p class="text-muted mb-0">Create, edit, delete and monitor status.</p></div><a class="btn btn-primary" href="<?=url('seeker/post_form.php')?>">+ New Post</a></div><div class="card shadow-soft table-card mt-4"><div class="table-responsive"><table class="table align-middle"><thead class="table-light"><tr><th>Post</th><th>Status</th><th>Applicants</th><th>Created</th><th>Actions</th></tr></thead><tbody><?php if(!$rows):?><tr><td colspan="5" class="empty-state">You have not created any tuition post.</td></tr><?php endif;foreach($rows as $r):?><tr><td><strong><?=e($r['title'])?></strong><br><small><?=e($r['subject'])?> • <?=e($r['location'])?></small></td><td><?=status_badge($r['status'])?></td><td><?= (int)$r['app_count'] ?></td><td><?=date('d M Y',strtotime($r['created_at']))?></td><td><div class="d-flex gap-2"><a class="btn btn-sm btn-outline-primary" href="<?=url('seeker/post_form.php?id='.$r['id'])?>">Edit</a><form method="post" action="<?=url('actions/delete_post.php')?>"><?=csrf_field()?><input type="hidden" name="id" value="<?=$r['id']?>"><button class="btn btn-sm btn-outline-danger" data-confirm="Delete this post and its applications?">Delete</button></form></div></td></tr><?php endforeach;?></tbody></table></div></div></div>
